Public class ETGCashewShipmentUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGCashewShipmentContract             ETGCashewShipmentContract;
    FormStringControl                       dimensionControl;

    DialogField                         fromDt,ToDt,CustId,Item,InvId;

}

Method.Source:
public void LookupCustId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conCustId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(CustTable));
    qbds.addSelectionField(fieldNum(CustTable,AccountNum));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conCustId);
}

public void LookupInvoiceId(FormStringControl _control)
{
    Query                   query = new Query();
    container               conInvId;
    QueryBuildDataSource    qbds;
    QueryBuildRange         qbr;

    qbds        = query.addDataSource(tableNum(CustInvoiceJour));
    qbds.addSelectionField(fieldNum(CustInvoiceJour,InvoiceId));
    SysLookupMultiSelectGrid::lookup(query,_control,_control,_control,conInvId);
}

public void build()
{
    int i;
    ETGCashewShipmentContract   contract;
    contract = this.dataContractObject() as ETGCashewShipmentContract;
    fromDt = this.addDialogField(methodStr(ETGCashewShipmentContract, parmfromdate),contract);
    ToDt = this.addDialogField(methodStr(ETGCashewShipmentContract, parmtodate),contract);
    CustId = this.addDialogField(methodStr(ETGCashewShipmentContract, parmCustAccount),contract);
    InvId = this.addDialogField(methodStr(ETGCashewShipmentContract, parmInvoiceId),contract);

}

public void postBuild()
{
    ETGCashewShipmentContract   contract;
    super();
    contract = this.dataContractObject() as ETGCashewShipmentContract;
    fromDt = this.bindInfo().getDialogField(contract,methodStr(ETGCashewShipmentContract, parmfromdate));
    ToDt = this.bindInfo().getDialogField(contract,methodStr(ETGCashewShipmentContract, parmtodate));
    CustId = this.bindInfo().getDialogField(contract,methodStr(ETGCashewShipmentContract, parmCustAccount));

    CustId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGCashewShipmentUIBuilder, lookupCustId),this);
    if (CustId)
    {
        CustId.lookupButton(2);
    }

    InvId = this.bindInfo().getDialogField(contract,methodStr(ETGCashewShipmentContract, parmInvoiceId));

    InvId.registerOverrideMethod(methodStr(FormStringControl, lookup),
    methodStr(ETGCashewShipmentUIBuilder, LookupInvoiceId),this);
    if (InvId)
    {
        InvId.lookupButton(2);
    }
}
